={{ (() => {
  const cfgItem = $items('SetConfig', 0, 0) || { json: {} };
  const cfg = cfgItem.json || {};
  const brand = cfg.BRAND || {};
  const primary = $json.primary || {};
  const related = Array.isArray($json.related) ? $json.related : [];
  const relatedLines = related.length
    ? related.map(r => `- ${r.title || ''} (${r.url || ''})`).join('\n')
    : '- 无参考';
  const primaryTextItem = $items('ReadPrimary', 0, 0) || { json: '' };
  const articleTextRaw = primaryTextItem.json;
  const articleText = typeof articleTextRaw === 'string'
    ? articleTextRaw
    : JSON.stringify(articleTextRaw || '');
  const palette = Array.isArray(brand.palette) ? brand.palette : [];
  const brandBlock = `BRAND: palette=${JSON.stringify(palette)}, style=${brand.style || ''}, negatives=${brand.negatives || ''}`;

  const systemMessage = `你是分析师与评论员。输出一个 JSON：{markdown, prompts}；
markdown=中文Markdown 1200-1600字，对用户提供的文章进行分析、提炼文章的主要内容和观点，并对其进行分析和评价；要求： 
1、文章结构和总体内容不变。不能泛泛而谈，要有细节，有情绪，有想法；不要随口胡说； 
2、像朋友之间一样，语言需要平等，没有说教感，说话的时候眉飞色舞的感觉； 
3、遣词造句要偏向口语化，偶尔体现一下自己的幽默感，不要太多的书面用语，多用短句，尽量少用长句； 
4、全篇写作要求（最重要，严格遵守）​
- 禁止使用书面关联用语例如：首先、然后、其次、再者说、总的来说、同时、殊不知、例如、除非、另一方面、否则、相反、因为、所以、近期、近来、与此同时、总而言之、换句话说、特别是、此外、换言之、最后、特别是等等，请使用口语化词汇​
- 禁止输出任何分隔线、破折号、符号、表格、代码块​
- 双引号要用「」号代替​- 不允许使用模板化结构。​
- 不允许重复使用同样的句式结构。​
- 偶尔可以有一些啰嗦的口头禅，或者不符合语法规范的话，避免太过完美。​
- 要像人一样说话，不要AI味儿，不要堆砌空话套话，要用口语化描述，避免学术化表达，增加活人感，比较新的名词或缩写要给出解释，让普通用户都能看得懂。
​- 加入个人情感和温度，不要使用客观、中立的陈述。 
- 禁止假大空的表达。​
- 需要有逻辑，能吸引人一直能读下去。 
- 打乱节奏：短句、长句、插入语混用，有时话没说完先岔开，有时补一句废话。 
- 减少整齐重复的句式：比如「他……他……」或者「你以为……结果……」不要一口气用两三次。 
- 用生活化的跳跃思维：偶尔加点没用的感叹、情绪插话，比如「我当时是真没想到」「这事要是换成我」。 
- 少用完美的逻辑串联：别一环套一环地写，可以像朋友聊天一样有点“跳”。 
- 多用细节词，不用套话：把「精彩」「节奏快」换成场景感强的描述，比如「看到凌晨两点还舍不得关手机」。 
- 多加几段小情绪插话，把人味拉满 
- 混用的、地、得 ，在不影响阅读的情况下，出现少量同音错别字；
- 输出风格偏口语化
- 一句话就一个段落，不要长段落；
- 标记图片插入位：在第一段后插入封面图 <!--IMG_COVER-->；
  根据文章内容，判断需要插入图片地方（两个图片之间间隔不少于 300 字），然后分别放如下标识： <!--IMG_KP1-->、<!--IMG_KP2-->、<!--IMG_KPn-->。
prompts=用于生成图片的提示词数组：封面+内容图片提示词（包含构图/隐喻/2-3主色/风格标记，禁止真实人物/商标），生成封面图片的提示词与全文内容匹配，内容图片的提示词需要与上下文匹配，与 markdown 中的图片插入位严格对应，内容中标识了多少个图片插入位，就必须有多少个提示词。风格与色板来自提供的 BRAND。`;

  const userMessage = `主要文章：${primary.title || ''}\n来源：${primary.source || ''}\n链接：${primary.url || ''}\n发布时间：${primary.publishedAt || ''}\n作者：${primary.author || ''}\n摘要：${primary.description || ''}\n\n正文全文（若缺失请谨慎）：\n${articleText}\n\n相关参考（仅标题与链接）：\n${relatedLines}\n\n${brandBlock}`;
  return JSON.stringify({
    model: cfg.OPENAI_CHAT || 'gpt-4o-mini',
    temperature: 0.4,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemMessage },
      { role: 'user', content: userMessage }
    ]
  });
})() }}

